  `eligibility` varchar(255) NOT NULL,
  `age_limit` varchar(255) NOT NULL,
  `exam_pattern` text NOT NULL,
  `difficulty_level` enum('Easy','Moderate','High','Very High') NOT NULL DEFAULT 'Moderate',
  `career_outcome` text NOT NULL,
  `description` text NOT NULL,
  `roadmap` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`roadmap`)),
  `prep_tips` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`prep_tips`)),
