INSERT INTO `competitive_exams` VALUES (1,'UPSC Civil Services Examination','upsc-civil-services-examination','Government Exams','Union Public Service Commission (UPSC)','Selection for IAS, IPS, IFS, and other Group A services.','Any Graduate (Degree from recognized University)','21 - 32 years (Relaxation for OBC/SC/ST)','Three Stages: Prelims (Objective), Mains (Descriptive), and Personality Test (Interview).','Very High','High-ranking Bureaucrat, Administrator, or Police Officer. Salary: ₹56,100 - ₹2,50,000+ PM.','The toughest and most prestigious exam in India for those who want to serve the nation at the highest level of administration.','[\"Foundation: Understand the syllabus and NCERT basics (6-12 months)\",\"Standard Books: Master subjects like History, Polity, Geography, and Economy\",\"Current Affairs: Daily Newspaper reading and monthly compilations\",\"Prelims Focus: Practice 50+ Mock Tests and PYQs\",\"Mains Focus: Answer writing practice and Optional subject mastery\",\"Interview: Personality development and mock interviews\"]','[\"Consistency is more important than number of hours\",\"Make concise notes for multiple revisions\",\"Analyze previous years papers to understand trend\",\"Do not ignore CSAT (Prelims Paper 2)\",\"Choose an Optional subject you are passionate about\"]','fa-landmark-flag','2026-04-27 13:18:05','2026-04-27 13:18:05'),(2,'IBPS PO (Probationary Officer)','ibps-po-probationary-officer','Banking Exams','Institute of Banking Personnel Selection','Recruitment for officers in Public Sector Banks.','Any Graduate','20 - 30 years','Prelims (Online Obj), Mains (Online Obj + Des), and Interview.','High','Bank Officer with rapid promotion to Management roles. Salary: ₹52,000 - ₹65,000 PM.','A fast-track career path in the banking sector with job security and excellent growth potential.','[\"Speed & Accuracy: Practice Vedic Maths and mental calculation\",\"Sections: Master Reasoning, Quant, and English separately\",\"General Awareness: Focus on Banking Awareness and Economy news\",\"Mock Tests: Take daily sectional tests and weekly full mocks\",\"Mains Writing: Practice letter and essay writing\"]','[\"Solve 50+ puzzles and 50+ DIs every week\",\"Focus on high-weightage topics like Data Interpretation\",\"Read economic times or financial express regularly\",\"Maintain a high accuracy rate even if you attempt fewer questions\"]','fa-building-columns','2026-04-27 13:18:05','2026-04-27 13:18:05'),(3,'JEE Advanced','jee-advanced','Entrance Exams','One of the seven IITs (on behalf of JAB)','Admission to Undergraduate Engineering programs in IITs.','12th Pass with PCM + Top rankers of JEE Main','Max 25 years (Relaxation applies)','Two Papers (Computer Based), both mandatory. Questions are highly conceptual.','Very High','Software Engineer, Researcher, Scientist, or Entrepreneur from world-class IITs.','Considered one of the most difficult engineering entrance exams globally, testing deep conceptual clarity.','[\"Concepts: Build 11th & 12th Physics, Chemistry, Maths foundation\",\"Problem Solving: Solve Irodov for Physics and Arihant\\/Cengage for Maths\",\"Mock Tests: Intense practice of previous year JEE Advanced papers\",\"Analysis: Identify weak topics after every test and re-read theory\"]','[\"Physics: Focus on Mechanics and Electrodynamics\",\"Maths: Practice Calculus and Coordinate Geometry daily\",\"Chemistry: Inorganic requires regular revision; Organic needs logic\",\"Health: Manage stress and sleep well during the final month\"]','fa-atom','2026-04-27 13:18:05','2026-04-27 13:18:05'),(4,'NDA (National Defence Academy)','nda-national-defence-academy','Defence Exams','UPSC','Entry into Army, Navy, and Air Force as Officers.','12th Pass (PCM for Navy/Air Force)','16.5 - 19.5 years','Written Exam (Maths + GAT) followed by SSB Interview (5 Days).','High','Lieutenant in Indian Army or equivalent. Prestigious life and adventure. Salary: ₹56,100+.','The premier joint services training institution of the Indian Armed Forces.','[\"Maths: Master 11th-12th Maths topics (300 Marks paper)\",\"English & GS: Improve vocabulary and Basic Science\\/SST knowledge\",\"Physical Fitness: Start running and basic bodyweight exercises\",\"SSB Preparation: Work on communication skills and leadership traits\"]','[\"Maths is the deciding factor; do not ignore it\",\"Be honest and confident for the SSB interview\",\"Stay updated with world affairs for the GD rounds\",\"Practice mental stamina for the 5-day selection process\"]','fa-shield-halved','2026-04-27 13:18:05','2026-04-27 13:18:05'),(5,'MPSC State Services','mpsc-state-services','Police Exams','Maharashtra Public Service Commission','Recruitment for DySP, ACP, and other State Gazetted posts.','Any Graduate (Marathi language knowledge required)','19 - 38 years (Relaxation for categories)','Prelims (Objective), Mains (Descriptive), and Interview.','High','Deputy Collector, DySP, Tehsildar. Powerful role in state governance.','The gateway for those wanting to serve in the Maharashtra State Government administration.','[\"Language: Master Marathi and English grammar\",\"State History: Deep dive into Maharashtra\'s history and geography\",\"Mains Preparation: Selective reading of GS1 to GS4 topics\",\"Test Series: Regular practice of descriptive answer writing\"]','[\"Read the MPSC specific state board books\",\"Watch local news and stay updated with state government schemes\",\"Practice Marathi typing if required for specific posts\",\"Focus on accuracy in the Prelims CSAT paper\"]','fa-person-military-pointing','2026-04-27 13:18:05','2026-04-27 13:18:05'),(6,'Chartered Accountancy (CA)','chartered-accountancy-ca','Professional Exams','The Institute of Chartered Accountants of India (ICAI)','Becoming a certified Chartered Accountant.','12th Pass (for Foundation) or Graduate (for Direct Entry)','No upper age limit','Three Levels: Foundation, Intermediate, and Final + Articleship training.','Very High','Auditor, Financial Consultant, or Tax Expert. Salary: ₹8L - ₹25L+ PA.','One of the most respected professional certifications globally for finance and accounting.','[\"Foundation: Build strong Accounting and Law basics\",\"Intermediate: Clear Group 1 and Group 2 with 8 months study\",\"Articleship: 2-3 years of practical training under a practicing CA\",\"Final: Toughest level; focus on SFM, FR, and Taxation\"]','[\"Focus on ICAI Study Material strictly\",\"Multiple revisions (at least 3) are mandatory\",\"Practice Mock Test Papers (MTP) and Revision Test Papers (RTP)\",\"Conceptual clarity is more important than rote learning\"]','fa-file-invoice-dollar','2026-04-27 13:18:05','2026-04-27 13:18:05');
/*!40000 ALTER TABLE `competitive_exams` ENABLE KEYS */;
UNLOCK TABLES;

