INSERT INTO `non_traditional_careers` VALUES (1,'Data Scientist','data-scientist','Tech & Digital Careers','Unlocking insights from big data to solve complex business problems.','Python, Statistics, Machine Learning, Data Visualization','[\"Step 1: Learn Statistics & Python\",\"Step 2: Master SQL and Data Libraries\",\"Step 3: Work on Real Datasets (Kaggle)\",\"Step 4: Build a Portfolio of Insights\"]','Jupyter, Pandas, Tableau, Scikit-learn','6-8 Months','₹6L - ₹20L PA','Job / Remote','Low','fa-database','2026-04-27 13:18:05','2026-04-27 13:18:05'),(2,'AI Engineer','ai-engineer','Tech & Digital Careers','Developing and deploying artificial intelligence models and neural networks.','Deep Learning, Neural Networks, PyTorch/TensorFlow','[\"Step 1: Master Python and Calculus\",\"Step 2: Learn Machine Learning Basics\",\"Step 3: Specialize in NLP or Computer Vision\",\"Step 4: Build AI Apps and Deploy on Cloud\"]','TensorFlow, PyTorch, OpenAI API, AWS','8-12 Months','₹8L - ₹30L PA','Job / Remote','Low','fa-brain','2026-04-27 13:18:05','2026-04-27 13:18:05'),(3,'Ethical Hacker','ethical-hacker','Tech & Digital Careers','Finding and fixing security vulnerabilities in computer systems and networks.','Networking, Linux, Penetration Testing, Python','[\"Step 1: Learn Networking & OS Basics\",\"Step 2: Get CEH or CompTIA Security+ Cert\",\"Step 3: Practice on TryHackMe or HackTheBox\",\"Step 4: Participate in Bug Bounties\"]','Kali Linux, Burp Suite, Metasploit, Wireshark','6-10 Months','₹5L - ₹18L PA','Job / Freelance','Low','fa-user-secret','2026-04-27 13:18:05','2026-04-27 13:18:05'),(4,'Animator','animator','Creative Careers','Bringing characters and stories to life through 2D or 3D animation.','Drawing, Timing, 3D Modeling, Storyboarding','[\"Step 1: Learn 12 Principles of Animation\",\"Step 2: Master Maya or Blender\",\"Step 3: Create a 30-second Animation Reel\",\"Step 4: Apply for Studios or Freelance\"]','Blender, Maya, After Effects, Toon Boom','12 Months','₹4L - ₹12L PA','Job / Freelance','Medium','fa-person-running','2026-04-27 13:18:05','2026-04-27 13:18:05'),(5,'Photographer','photographer','Creative Careers','Capturing moments, products, or landscapes with professional precision.','Composition, Lighting, Photo Editing, Business Networking','[\"Step 1: Learn Camera Manual Settings\",\"Step 2: Master Lighting and Framing\",\"Step 3: Learn Post-processing (Lightroom)\",\"Step 4: Build an Instagram Portfolio & Network\"]','DSLR/Mirrorless, Adobe Lightroom, Photoshop','4-6 Months','₹30K - ₹2L PM','Freelance / Business','Medium','fa-camera-retro','2026-04-27 13:18:05','2026-04-27 13:18:05'),(6,'YouTuber','youtuber','Social Media Careers','Creating video content and building a loyal community on YouTube.','Content Planning, Video Editing, SEO, Consistency','[\"Step 1: Choose a Profitable Niche\",\"Step 2: Learn Basic Filming & Editing\",\"Step 3: Understand YouTube Algorithm & SEO\",\"Step 4: Post Weekly and Build Community\"]','YouTube, Premiere Pro, Canva, VidIQ','6-12 Months (Growth)','₹10K - ₹10L+ PM','Self-employed / Business','High','fa-youtube','2026-04-27 13:18:05','2026-04-27 13:18:05'),(7,'Game Developer','game-developer','Gaming Careers','Programming and building the mechanics of video games.','C#, C++, Unity/Unreal Engine, Game Math','[\"Step 1: Learn Programming Basics (C#)\",\"Step 2: Master Unity or Unreal Engine\",\"Step 3: Build 2 Small Games for Portfolio\",\"Step 4: Publish on Play Store or Steam\"]','Unity, Unreal Engine, GitHub, Visual Studio','8-12 Months','₹5L - ₹20L PA','Job / Freelance / Business','Low','fa-code','2026-04-27 13:18:05','2026-04-27 13:18:05'),(8,'Game Tester','game-tester','Gaming Careers','Finding bugs and providing feedback to improve game quality.','Attention to Detail, Quality Assurance, Bug Reporting','[\"Step 1: Understand Game Development Lifecycle\",\"Step 2: Learn Bug Tracking Tools (Jira)\",\"Step 3: Practice Systematic Testing\",\"Step 4: Apply for QA roles at Game Studios\"]','Jira, Excel, Bugzilla, Console/PC','2-3 Months','₹2.5L - ₹6L PA','Job','Low','fa-bug','2026-04-27 13:18:05','2026-04-27 13:18:05'),(9,'Digital Marketer','digital-marketer','Freelancing & Remote Work','Helping brands grow online through SEO, Ads, and Social Media.','SEO, SEM, Copywriting, Data Analytics','[\"Step 1: Understand Digital Marketing Basics\",\"Step 2: Get Certified (Google\\/HubSpot)\",\"Step 3: Run Small Campaigns or Freelance\",\"Step 4: Work as a Consultant or Agency\"]','Google Ads, Meta Ads Manager, SEMrush','4 Months','₹40K - ₹3L PM','Freelance / Job / Business','Low','fa-chart-line','2026-04-27 13:18:05','2026-04-27 13:18:05');
